import{c as a,Q as o,j as t,m as r}from"./chunks/framework.rlpw0eGz.js";const h=JSON.parse('{"title":"Desktop 桌面版安装","description":"","frontmatter":{},"headers":[],"relativePath":"zh/installation/desktop.md","filePath":"zh/installation/desktop.md","lastUpdated":1778736656000}'),l={name:"zh/installation/desktop.md"};function i(s,e,d,p,c,n){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="desktop-桌面版安装" tabindex="-1">Desktop 桌面版安装 <a class="header-anchor" href="#desktop-桌面版安装" aria-label="Permalink to &quot;Desktop 桌面版安装&quot;">​</a></h1><p>Memoh Desktop 是面向个人和本地使用的原生客户端。它和 Server Deploy 是两条分发线：桌面版默认管理自己的本地后端，而不是连接一个托管的 Web/server 部署。</p><h2 id="什么时候用-desktop" tabindex="-1">什么时候用 Desktop <a class="header-anchor" href="#什么时候用-desktop" aria-label="Permalink to &quot;什么时候用 Desktop&quot;">​</a></h2><p>适合这些场景：</p><ul><li>想要一个打开就能用的本地 App</li><li>单用户或个人工作流</li><li>本地记忆和本地存储</li><li>想用 bundled <code>memoh</code> CLI 连接同一个本地服务</li><li>在自己的电脑上使用 local 或 Docker-backed workspace</li></ul><p>如果你需要多人共享、生产可用性、远程访问，或机器人要在桌面离线时继续服务外部渠道，请用 <a href="/zh/installation/docker.html">Server Deploy</a>。</p><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><ol><li>从 <a href="https://memoh.ai/desktop" target="_blank" rel="noreferrer">Memoh Desktop 下载页</a> 下载对应平台安装包。</li><li>打开 Memoh。</li><li>等 App 启动本地服务并初始化存储。</li><li>可选：在 App 菜单里安装 bundled <code>memoh</code> CLI。</li></ol><h2 id="desktop-会管理什么" tabindex="-1">Desktop 会管理什么 <a class="header-anchor" href="#desktop-会管理什么" aria-label="Permalink to &quot;Desktop 会管理什么&quot;">​</a></h2><p>桌面版负责本地运行时生命周期：</p><ul><li><code>127.0.0.1:18731</code> 上的本地 <code>memoh-server</code></li><li>系统应用数据目录下的 SQLite 本地数据</li><li>用于记忆向量检索的 embedded Qdrant</li><li>bundled CLI、server binary、provider templates、workspace bridge runtime</li><li>系统托盘唤起与退出行为</li></ul><p>从托盘退出会走桌面端的关闭路径，同时停止它管理的本地 server 和 embedded Qdrant。</p><h2 id="workspace-行为" tabindex="-1">Workspace 行为 <a class="header-anchor" href="#workspace-行为" aria-label="Permalink to &quot;Workspace 行为&quot;">​</a></h2><p>Desktop 可按配置使用 trusted local workspace 或 container-backed workspace。Trusted local workspace 以本地用户权限运行，不提供容器隔离；container-backed workspace 仍保留正常的 bot workspace 模型，可用于文件编辑、命令执行、MCP 托管，以及可选的桌面显示/浏览器会话。</p><p>运行时差异见 <a href="/zh/installation/workspace-backends.html">Workspace backend</a>。</p>',15)])])}const m=a(l,[["render",i]]);export{h as __pageData,m as default};
